function solve(nums: number[], k: number): number {
    let prefixSum = 0;
    let dp = 0;
    const modMap: { [key: number]: number } = { 0: 0 };
    for (const num of nums) {
        prefixSum += num;
        const modVal = prefixSum % k;
        let candidate = dp;
        if (modVal in modMap) {
            const prevValue = modMap[modVal];
            candidate = Math.max(dp, prevValue + prefixSum);
        }
        dp = candidate;
        const currentVal = dp - prefixSum;
        if (modVal in modMap) {
            if (currentVal > modMap[modVal]) {
                modMap[modVal] = currentVal;
            }
        } else {
            modMap[modVal] = currentVal;
        }
    }
    const totalSum = nums.reduce((a, b) => a + b, 0);
    return totalSum - dp;
}

